-- ── 일산룸 (일산 룸) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산룸에서 모임했는데 만족', '회사 동료들이랑 일산룸에서 모임했는데 룸 크기가 딱 좋았음. 음향 시설도 괜찮고 서비스도 빠름. 신실장이 세팅 잘 해줘서 불편한 거 없이 잘 놀았음. 일산에서 프라이빗하게 놀기 좋은 곳.', 'ilsanroom', 5, 16, 79, false, '2026-04-04T06:46:25.427Z', '2026-04-04T06:46:25.427Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산 룸 여기 추천', '몇 군데 비교해봤는데 일산룸이 시설 면에서 가장 나았음. 룸 종류도 다양하고 인원수에 맞게 추천해줌. 양주 라인업도 괜찮고. 프라이빗한 공간이 필요하면 여기 가면 됨.', 'ilsanroom', 4, 31, 218, false, '2026-04-06T03:59:22.639Z', '2026-04-06T03:59:22.639Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '일산룸 처음 가는 분들 팁', '일산룸 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

일산 룸 중에 일산룸이 무난하고 좋음.', NULL, NULL, 6, 233, false, '2026-04-16T14:01:55.989Z', '2026-04-16T14:01:55.989Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산룸 가보신 분?', '일산에서 룸 가보려고 하는데 일산룸 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 206, false, '2026-04-28T23:01:27.567Z', '2026-04-28T23:01:27.567Z');

-- ── 해운대고구려 (부산 해운대 룸) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '해운대고구려에서 모임했는데 만족', '회사 동료들이랑 해운대고구려에서 모임했는데 룸 크기가 딱 좋았음. 음향 시설도 괜찮고 서비스도 빠름. 불편한 거 없이 잘 놀았음. 부산 해운대에서 프라이빗하게 놀기 좋은 곳.', 'haeundaegoguryeo', 5, 21, 183, false, '2026-04-06T20:19:40.254Z', '2026-04-06T20:19:40.254Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '부산 해운대 룸 여기 추천', '몇 군데 비교해봤는데 해운대고구려이 시설 면에서 가장 나았음. 룸 종류도 다양하고 인원수에 맞게 추천해줌. 양주 라인업도 괜찮고. 프라이빗한 공간이 필요하면 여기 가면 됨.', 'haeundaegoguryeo', 4, 34, 228, false, '2026-04-23T00:43:20.266Z', '2026-04-23T00:43:20.266Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '해운대고구려 처음 가는 분들 팁', '해운대고구려 몇 번 가봤는데 알게 된 것들 공유함.

