INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산명월관요정 가보신 분?', '일산에서 요정 가보려고 하는데 일산명월관요정 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 7, 167, false, '2026-04-12T17:33:00.280Z', '2026-04-12T17:33:00.280Z');

-- ── 청담H2O나이트 (청담 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청담H2O나이트 첫 방문 후기', '청담에서 나이트 찾다가 청담H2O나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 펩시맨 실장한테 자리 안내받았는데 센스있더라. 다음 주말에 또 갈 예정.', 'cheongdamh2onight', 5, 14, 55, false, '2026-04-06T18:17:14.205Z', '2026-04-06T18:17:14.205Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 청담H2O나이트 다녀왔습니다', '친구가 청담H2O나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 청담 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'cheongdamh2onight', 4, 10, 115, false, '2026-04-14T13:32:12.005Z', '2026-04-14T13:32:12.005Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청담 나이트 비교해봤는데', '청담에서 나이트 3군데 돌아봤는데 청담H2O나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'cheongdamh2onight', 5, 5, 198, false, '2026-04-15T20:17:54.652Z', '2026-04-15T20:17:54.652Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '청담H2O나이트 처음 가는 분들 팁', '청담H2O나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

청담 나이트 중에 청담H2O나이트이 무난하고 좋음.', NULL, NULL, 9, 203, false, '2026-04-01T07:22:27.524Z', '2026-04-01T07:22:27.524Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '청담H2O나이트 가보신 분?', '청담에서 나이트 가보려고 하는데 청담H2O나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 7, 51, false, '2026-04-26T22:29:21.467Z', '2026-04-26T22:29:21.467Z');

-- ── 강남줄리아나나이트 (강남 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강남줄리아나나이트 첫 방문 후기', '강남에서 나이트 찾다가 강남줄리아나나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gangnamjuliananight', 5, 27, 89, false, '2026-04-17T11:38:07.230Z', '2026-04-17T11:38:07.230Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 강남줄리아나나이트 다녀왔습니다', '친구가 강남줄리아나나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 강남 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gangnamjuliananight', 4, 33, 224, false, '2026-04-27T16:07:59.279Z', '2026-04-27T16:07:59.279Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강남 나이트 비교해봤는데', '강남에서 나이트 3군데 돌아봤는데 강남줄리아나나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gangnamjuliananight', 5, 18, 119, false, '2026-04-07T05:41:11.758Z', '2026-04-07T05:41:11.758Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '강남줄리아나나이트 처음 가는 분들 팁', '강남줄리아나나이트 몇 번 가봤는데 알게 된 것들 공유함.

