INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강서나이트 첫 방문 후기', '강서에서 나이트 찾다가 강서나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gangseonight', 5, 21, 208, false, '2026-04-11T09:42:10.384Z', '2026-04-11T09:42:10.384Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 강서나이트 다녀왔습니다', '친구가 강서나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 강서 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gangseonight', 4, 15, 185, false, '2026-03-30T15:41:00.853Z', '2026-03-30T15:41:00.853Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강서 나이트 비교해봤는데', '강서에서 나이트 3군데 돌아봤는데 강서나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gangseonight', 5, 12, 190, false, '2026-04-04T19:03:11.176Z', '2026-04-04T19:03:11.176Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '강서나이트 처음 가는 분들 팁', '강서나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

강서 나이트 중에 강서나이트이 무난하고 좋음.', NULL, NULL, 12, 144, false, '2026-04-17T03:48:43.195Z', '2026-04-17T03:48:43.195Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '강서나이트 가보신 분?', '강서에서 나이트 가보려고 하는데 강서나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 5, 183, false, '2026-04-13T14:25:55.718Z', '2026-04-13T14:25:55.718Z');

-- ── 영등포터미널나이트 (영등포 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '영등포터미널나이트 첫 방문 후기', '영등포에서 나이트 찾다가 영등포터미널나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'yeongdeungpoterminalnight', 5, 10, 136, false, '2026-04-07T16:30:42.238Z', '2026-04-07T16:30:42.238Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 영등포터미널나이트 다녀왔습니다', '친구가 영등포터미널나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 영등포 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'yeongdeungpoterminalnight', 4, 6, 85, false, '2026-04-08T18:45:27.730Z', '2026-04-08T18:45:27.730Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '영등포 나이트 비교해봤는데', '영등포에서 나이트 3군데 돌아봤는데 영등포터미널나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'yeongdeungpoterminalnight', 5, 11, 129, false, '2026-04-09T16:23:08.647Z', '2026-04-09T16:23:08.647Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '영등포터미널나이트 처음 가는 분들 팁', '영등포터미널나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

영등포 나이트 중에 영등포터미널나이트이 무난하고 좋음.', NULL, NULL, 30, 199, false, '2026-04-24T02:22:28.925Z', '2026-04-24T02:22:28.925Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '영등포터미널나이트 가보신 분?', '영등포에서 나이트 가보려고 하는데 영등포터미널나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 26, 64, false, '2026-04-03T18:52:11.450Z', '2026-04-03T18:52:11.450Z');

