INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '길동찬스나이트 가보신 분?', '길동에서 나이트 가보려고 하는데 길동찬스나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 31, 222, false, '2026-04-20T14:34:30.565Z', '2026-04-20T14:34:30.565Z');

-- ── 일산샴푸나이트 (일산 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산샴푸나이트 첫 방문 후기', '일산에서 나이트 찾다가 일산샴푸나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'ilsanshampoonight', 5, 30, 130, false, '2026-04-08T13:54:29.881Z', '2026-04-08T13:54:29.881Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 일산샴푸나이트 다녀왔습니다', '친구가 일산샴푸나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 일산 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'ilsanshampoonight', 4, 13, 72, false, '2026-04-21T20:13:17.067Z', '2026-04-21T20:13:17.067Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산 나이트 비교해봤는데', '일산에서 나이트 3군데 돌아봤는데 일산샴푸나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'ilsanshampoonight', 5, 8, 122, false, '2026-04-15T08:03:27.764Z', '2026-04-15T08:03:27.764Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '일산샴푸나이트 처음 가는 분들 팁', '일산샴푸나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

일산 나이트 중에 일산샴푸나이트이 무난하고 좋음.', NULL, NULL, 10, 111, false, '2026-04-02T07:18:55.215Z', '2026-04-02T07:18:55.215Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산샴푸나이트 가보신 분?', '일산에서 나이트 가보려고 하는데 일산샴푸나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 62, false, '2026-04-08T11:26:48.319Z', '2026-04-08T11:26:48.319Z');

-- ── 파주야당스카이돔나이트 (파주 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '파주야당스카이돔나이트 첫 방문 후기', '파주에서 나이트 찾다가 파주야당스카이돔나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 막내 실장한테 자리 안내받았는데 센스있더라. 다음 주말에 또 갈 예정.', 'pajuyadangskydomenight', 5, 21, 59, false, '2026-04-09T06:24:27.362Z', '2026-04-09T06:24:27.362Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 파주야당스카이돔나이트 다녀왔습니다', '친구가 파주야당스카이돔나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 파주 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'pajuyadangskydomenight', 4, 27, 173, false, '2026-04-16T00:50:23.346Z', '2026-04-16T00:50:23.346Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '파주 나이트 비교해봤는데', '파주에서 나이트 3군데 돌아봤는데 파주야당스카이돔나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'pajuyadangskydomenight', 5, 32, 144, false, '2026-04-10T22:01:14.334Z', '2026-04-10T22:01:14.334Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '파주야당스카이돔나이트 처음 가는 분들 팁', '파주야당스카이돔나이트 몇 번 가봤는데 알게 된 것들 공유함.

