INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '김포썸나이트 첫 방문 후기', '김포에서 나이트 찾다가 김포썸나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gimposomenight', 5, 20, 131, false, '2026-04-18T19:48:23.912Z', '2026-04-18T19:48:23.912Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 김포썸나이트 다녀왔습니다', '친구가 김포썸나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 김포 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gimposomenight', 4, 32, 176, false, '2026-04-10T01:24:58.420Z', '2026-04-10T01:24:58.420Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '김포 나이트 비교해봤는데', '김포에서 나이트 3군데 돌아봤는데 김포썸나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gimposomenight', 5, 26, 74, false, '2026-04-18T17:31:31.747Z', '2026-04-18T17:31:31.747Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '김포썸나이트 처음 가는 분들 팁', '김포썸나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

김포 나이트 중에 김포썸나이트이 무난하고 좋음.', NULL, NULL, 12, 64, false, '2026-03-30T04:21:22.052Z', '2026-03-30T04:21:22.052Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '김포썸나이트 가보신 분?', '김포에서 나이트 가보려고 하는데 김포썸나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 22, 238, false, '2026-04-08T17:50:58.067Z', '2026-04-08T17:50:58.067Z');

-- ── 구리호박나이트 (구리 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '구리호박나이트 첫 방문 후기', '구리에서 나이트 찾다가 구리호박나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gurihobaknight', 5, 10, 207, false, '2026-04-10T06:52:11.687Z', '2026-04-10T06:52:11.687Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 구리호박나이트 다녀왔습니다', '친구가 구리호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 구리 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gurihobaknight', 4, 16, 185, false, '2026-04-15T10:05:19.791Z', '2026-04-15T10:05:19.791Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '구리 나이트 비교해봤는데', '구리에서 나이트 3군데 돌아봤는데 구리호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gurihobaknight', 5, 6, 131, false, '2026-04-02T06:53:27.430Z', '2026-04-02T06:53:27.430Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '구리호박나이트 처음 가는 분들 팁', '구리호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

구리 나이트 중에 구리호박나이트이 무난하고 좋음.', NULL, NULL, 26, 245, false, '2026-03-30T20:45:31.847Z', '2026-03-30T20:45:31.847Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '구리호박나이트 가보신 분?', '구리에서 나이트 가보려고 하는데 구리호박나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 33, 115, false, '2026-04-02T03:14:10.218Z', '2026-04-02T03:14:10.218Z');

-- ── 의정부한국관나이트 (의정부 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '의정부한국관나이트 첫 방문 후기', '의정부에서 나이트 찾다가 의정부한국관나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'uijeongbuhangukgwannight', 5, 12, 219, false, '2026-04-18T01:55:35.292Z', '2026-04-18T01:55:35.292Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 의정부한국관나이트 다녀왔습니다', '친구가 의정부한국관나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 의정부 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'uijeongbuhangukgwannight', 4, 23, 203, false, '2026-04-22T15:56:27.017Z', '2026-04-22T15:56:27.017Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '의정부 나이트 비교해봤는데', '의정부에서 나이트 3군데 돌아봤는데 의정부한국관나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'uijeongbuhangukgwannight', 5, 33, 242, false, '2026-04-11T09:49:10.450Z', '2026-04-11T09:49:10.450Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '의정부한국관나이트 처음 가는 분들 팁', '의정부한국관나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

의정부 나이트 중에 의정부한국관나이트이 무난하고 좋음.', NULL, NULL, 7, 213, false, '2026-04-28T03:54:15.481Z', '2026-04-28T03:54:15.481Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '의정부한국관나이트 가보신 분?', '의정부에서 나이트 가보려고 하는데 의정부한국관나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 14, 117, false, '2026-04-03T07:34:17.024Z', '2026-04-03T07:34:17.024Z');

-- ── 수원찬스돔나이트 (수원 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '수원찬스돔나이트 첫 방문 후기', '수원에서 나이트 찾다가 수원찬스돔나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 강호동 실장한테 자리 안내받았는데 센스있더라. 다음 주말에 또 갈 예정.', 'suwonchancenight', 5, 26, 53, false, '2026-04-24T02:58:56.642Z', '2026-04-24T02:58:56.642Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 수원찬스돔나이트 다녀왔습니다', '친구가 수원찬스돔나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 수원 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'suwonchancenight', 4, 33, 217, false, '2026-04-07T00:49:27.986Z', '2026-04-07T00:49:27.986Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '수원 나이트 비교해봤는데', '수원에서 나이트 3군데 돌아봤는데 수원찬스돔나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'suwonchancenight', 5, 14, 159, false, '2026-04-11T18:48:15.336Z', '2026-04-11T18:48:15.336Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '수원찬스돔나이트 처음 가는 분들 팁', '수원찬스돔나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

수원 나이트 중에 수원찬스돔나이트이 무난하고 좋음.', NULL, NULL, 15, 238, false, '2026-04-09T06:17:29.710Z', '2026-04-09T06:17:29.710Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '수원찬스돔나이트 가보신 분?', '수원에서 나이트 가보려고 하는데 수원찬스돔나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 8, 179, false, '2026-04-14T13:35:45.963Z', '2026-04-14T13:35:45.963Z');

