INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '인덕원 나이트 비교해봤는데', '인덕원에서 나이트 3군데 돌아봤는데 인덕원국빈관나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'indeokvon-gukbingwan-night', 5, 21, 231, false, '2026-03-31T07:21:36.301Z', '2026-03-31T07:21:36.301Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '인덕원국빈관나이트 처음 가는 분들 팁', '인덕원국빈관나이트 몇 번 가봤는데 알게 된 것들 공유함.

