INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '분당퐁퐁나이트 첫 방문 후기', '분당에서 나이트 찾다가 분당퐁퐁나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'bundangpongpongnight', 5, 13, 77, false, '2026-04-12T22:59:00.012Z', '2026-04-12T22:59:00.012Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 분당퐁퐁나이트 다녀왔습니다', '친구가 분당퐁퐁나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 분당 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'bundangpongpongnight', 4, 30, 204, false, '2026-04-21T11:11:48.618Z', '2026-04-21T11:11:48.618Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '분당 나이트 비교해봤는데', '분당에서 나이트 3군데 돌아봤는데 분당퐁퐁나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'bundangpongpongnight', 5, 31, 229, false, '2026-04-14T13:41:21.698Z', '2026-04-14T13:41:21.698Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '분당퐁퐁나이트 처음 가는 분들 팁', '분당퐁퐁나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

분당 나이트 중에 분당퐁퐁나이트이 무난하고 좋음.', NULL, NULL, 25, 111, false, '2026-04-03T15:37:24.560Z', '2026-04-03T15:37:24.560Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '분당퐁퐁나이트 가보신 분?', '분당에서 나이트 가보려고 하는데 분당퐁퐁나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 14, 50, false, '2026-04-15T11:14:14.579Z', '2026-04-15T11:14:14.579Z');

-- ── 평택호박나이트 (평택 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '평택호박나이트 첫 방문 후기', '평택에서 나이트 찾다가 평택호박나이트 갔는데 진짜 괜찮았음. 댄스홀, 라이브 음악 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'pyeongtaekhobaknight', 5, 9, 202, false, '2026-04-22T21:18:03.589Z', '2026-04-22T21:18:03.589Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 평택호박나이트 다녀왔습니다', '친구가 평택호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 평택 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'pyeongtaekhobaknight', 4, 18, 99, false, '2026-04-08T07:33:55.330Z', '2026-04-08T07:33:55.330Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '평택 나이트 비교해봤는데', '평택에서 나이트 3군데 돌아봤는데 평택호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'pyeongtaekhobaknight', 5, 21, 162, false, '2026-04-09T01:51:40.323Z', '2026-04-09T01:51:40.323Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '평택호박나이트 처음 가는 분들 팁', '평택호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

평택 나이트 중에 평택호박나이트이 무난하고 좋음.', NULL, NULL, 7, 214, false, '2026-04-08T17:07:20.326Z', '2026-04-08T17:07:20.326Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '평택호박나이트 가보신 분?', '평택에서 나이트 가보려고 하는데 평택호박나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 24, 57, false, '2026-04-20T22:57:07.998Z', '2026-04-20T22:57:07.998Z');

-- ── 인천아라비안나이트 (인천 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '인천아라비안나이트 첫 방문 후기', '인천에서 나이트 찾다가 인천아라비안나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'incheonarabiannight', 5, 23, 176, false, '2026-03-31T01:15:26.542Z', '2026-03-31T01:15:26.542Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 인천아라비안나이트 다녀왔습니다', '친구가 인천아라비안나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 인천 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'incheonarabiannight', 4, 8, 164, false, '2026-04-13T09:49:07.243Z', '2026-04-13T09:49:07.243Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '인천 나이트 비교해봤는데', '인천에서 나이트 3군데 돌아봤는데 인천아라비안나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'incheonarabiannight', 5, 16, 143, false, '2026-04-22T22:33:42.685Z', '2026-04-22T22:33:42.685Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '인천아라비안나이트 처음 가는 분들 팁', '인천아라비안나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

인천 나이트 중에 인천아라비안나이트이 무난하고 좋음.', NULL, NULL, 28, 211, false, '2026-04-20T14:10:50.584Z', '2026-04-20T14:10:50.584Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '인천아라비안나이트 가보신 분?', '인천에서 나이트 가보려고 하는데 인천아라비안나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 30, 245, false, '2026-04-19T22:32:01.382Z', '2026-04-19T22:32:01.382Z');

