INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '부천메리트나이트 첫 방문 후기', '부천에서 나이트 찾다가 부천메리트나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'bucheonmeritnight', 5, 14, 91, false, '2026-04-17T10:14:08.415Z', '2026-04-17T10:14:08.415Z');
