INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '부천메리트나이트 처음 가는 분들 팁', '부천메리트나이트 몇 번 가봤는데 알게 된 것들 공유함.

