INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '천안 나이트 비교해봤는데', '천안에서 나이트 3군데 돌아봤는데 천안스타돔나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'cheonanstardomnight', 5, 17, 187, false, '2026-04-03T23:42:54.289Z', '2026-04-03T23:42:54.289Z');
