INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대전세븐나이트 다녀왔습니다', '친구가 대전세븐나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대전 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daejeonsevennight', 4, 8, 57, false, '2026-04-08T15:15:46.678Z', '2026-04-08T15:15:46.678Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전 나이트 비교해봤는데', '대전에서 나이트 3군데 돌아봤는데 대전세븐나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daejeonsevennight', 5, 29, 146, false, '2026-04-20T19:57:11.410Z', '2026-04-20T19:57:11.410Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대전세븐나이트 처음 가는 분들 팁', '대전세븐나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대전 나이트 중에 대전세븐나이트이 무난하고 좋음.', NULL, NULL, 26, 132, false, '2026-04-06T20:02:47.044Z', '2026-04-06T20:02:47.044Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대전세븐나이트 가보신 분?', '대전에서 나이트 가보려고 하는데 대전세븐나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 13, 119, false, '2026-04-03T05:43:47.598Z', '2026-04-03T05:43:47.598Z');

-- ── 대전원나이트 (대전 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전원나이트 첫 방문 후기', '대전에서 나이트 찾다가 대전원나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daejeononenight', 5, 13, 106, false, '2026-04-14T12:37:37.762Z', '2026-04-14T12:37:37.762Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대전원나이트 다녀왔습니다', '친구가 대전원나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대전 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daejeononenight', 4, 29, 238, false, '2026-04-13T13:49:23.473Z', '2026-04-13T13:49:23.473Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전 나이트 비교해봤는데', '대전에서 나이트 3군데 돌아봤는데 대전원나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daejeononenight', 5, 10, 89, false, '2026-04-17T04:52:07.596Z', '2026-04-17T04:52:07.596Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대전원나이트 처음 가는 분들 팁', '대전원나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대전 나이트 중에 대전원나이트이 무난하고 좋음.', NULL, NULL, 21, 117, false, '2026-04-08T20:39:37.023Z', '2026-04-08T20:39:37.023Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대전원나이트 가보신 분?', '대전에서 나이트 가보려고 하는데 대전원나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 24, 135, false, '2026-04-14T10:28:09.038Z', '2026-04-14T10:28:09.038Z');

-- ── 대전봉명나이트 (대전 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전봉명나이트 첫 방문 후기', '대전에서 나이트 찾다가 대전봉명나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daejeonbongmyeongnight', 5, 6, 97, false, '2026-04-05T17:49:26.986Z', '2026-04-05T17:49:26.986Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대전봉명나이트 다녀왔습니다', '친구가 대전봉명나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대전 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daejeonbongmyeongnight', 4, 27, 193, false, '2026-04-27T14:50:01.646Z', '2026-04-27T14:50:01.646Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전 나이트 비교해봤는데', '대전에서 나이트 3군데 돌아봤는데 대전봉명나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daejeonbongmyeongnight', 5, 31, 126, false, '2026-04-14T01:29:28.470Z', '2026-04-14T01:29:28.470Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대전봉명나이트 처음 가는 분들 팁', '대전봉명나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대전 나이트 중에 대전봉명나이트이 무난하고 좋음.', NULL, NULL, 11, 137, false, '2026-04-02T22:59:25.727Z', '2026-04-02T22:59:25.727Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대전봉명나이트 가보신 분?', '대전에서 나이트 가보려고 하는데 대전봉명나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 33, 196, false, '2026-04-25T21:08:53.632Z', '2026-04-25T21:08:53.632Z');

-- ── 대전한국관나이트 (대전 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전한국관나이트 첫 방문 후기', '대전에서 나이트 찾다가 대전한국관나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daejeonhangukgwannight', 5, 5, 123, false, '2026-04-16T10:20:57.968Z', '2026-04-16T10:20:57.968Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대전한국관나이트 다녀왔습니다', '친구가 대전한국관나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대전 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daejeonhangukgwannight', 4, 8, 77, false, '2026-04-04T12:27:53.248Z', '2026-04-04T12:27:53.248Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전 나이트 비교해봤는데', '대전에서 나이트 3군데 돌아봤는데 대전한국관나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daejeonhangukgwannight', 5, 28, 211, false, '2026-04-03T03:09:42.665Z', '2026-04-03T03:09:42.665Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대전한국관나이트 처음 가는 분들 팁', '대전한국관나이트 몇 번 가봤는데 알게 된 것들 공유함.

