INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '청주돈텔마마나이트 가보신 분?', '청주에서 나이트 가보려고 하는데 청주돈텔마마나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 30, 218, false, '2026-03-30T11:08:43.690Z', '2026-03-30T11:08:43.690Z');

-- ── 청주호박나이트 (청주 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청주호박나이트 첫 방문 후기', '청주에서 나이트 찾다가 청주호박나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'cheongjuhobaknight', 5, 30, 170, false, '2026-04-26T23:05:06.899Z', '2026-04-26T23:05:06.899Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 청주호박나이트 다녀왔습니다', '친구가 청주호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 청주 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'cheongjuhobaknight', 4, 34, 143, false, '2026-04-25T08:25:29.027Z', '2026-04-25T08:25:29.027Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청주 나이트 비교해봤는데', '청주에서 나이트 3군데 돌아봤는데 청주호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'cheongjuhobaknight', 5, 9, 240, false, '2026-04-01T03:40:11.776Z', '2026-04-01T03:40:11.776Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '청주호박나이트 처음 가는 분들 팁', '청주호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

청주 나이트 중에 청주호박나이트이 무난하고 좋음.', NULL, NULL, 9, 140, false, '2026-04-02T03:06:29.794Z', '2026-04-02T03:06:29.794Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '청주호박나이트 가보신 분?', '청주에서 나이트 가보려고 하는데 청주호박나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 21, 128, false, '2026-04-22T17:31:43.909Z', '2026-04-22T17:31:43.909Z');

-- ── 서산호박나이트 (서산 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '서산호박나이트 첫 방문 후기', '서산에서 나이트 찾다가 서산호박나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'seosanhobaknight', 5, 34, 210, false, '2026-04-02T01:03:08.591Z', '2026-04-02T01:03:08.591Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 서산호박나이트 다녀왔습니다', '친구가 서산호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 서산 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'seosanhobaknight', 4, 28, 164, false, '2026-04-01T13:50:09.149Z', '2026-04-01T13:50:09.149Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '서산 나이트 비교해봤는데', '서산에서 나이트 3군데 돌아봤는데 서산호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'seosanhobaknight', 5, 26, 55, false, '2026-04-10T16:41:44.954Z', '2026-04-10T16:41:44.954Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '서산호박나이트 처음 가는 분들 팁', '서산호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

서산 나이트 중에 서산호박나이트이 무난하고 좋음.', NULL, NULL, 27, 232, false, '2026-04-02T04:06:34.931Z', '2026-04-02T04:06:34.931Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '서산호박나이트 가보신 분?', '서산에서 나이트 가보려고 하는데 서산호박나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 27, 213, false, '2026-04-21T06:40:58.084Z', '2026-04-21T06:40:58.084Z');

-- ── 대구한국관나이트 (대구 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구한국관나이트 첫 방문 후기', '대구에서 나이트 찾다가 대구한국관나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daeguhangukgwannight', 5, 14, 186, false, '2026-04-22T03:29:31.489Z', '2026-04-22T03:29:31.489Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대구한국관나이트 다녀왔습니다', '친구가 대구한국관나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대구 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daeguhangukgwannight', 4, 26, 122, false, '2026-04-26T02:34:04.598Z', '2026-04-26T02:34:04.598Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구 나이트 비교해봤는데', '대구에서 나이트 3군데 돌아봤는데 대구한국관나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daeguhangukgwannight', 5, 20, 205, false, '2026-04-25T10:41:47.642Z', '2026-04-25T10:41:47.642Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대구한국관나이트 처음 가는 분들 팁', '대구한국관나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대구 나이트 중에 대구한국관나이트이 무난하고 좋음.', NULL, NULL, 32, 90, false, '2026-04-09T18:03:08.074Z', '2026-04-09T18:03:08.074Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대구한국관나이트 가보신 분?', '대구에서 나이트 가보려고 하는데 대구한국관나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 24, 106, false, '2026-04-23T22:20:54.122Z', '2026-04-23T22:20:54.122Z');

