INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구호박나이트 첫 방문 후기', '대구에서 나이트 찾다가 대구호박나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daeguhobaknight', 5, 34, 172, false, '2026-04-25T19:09:29.110Z', '2026-04-25T19:09:29.110Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대구호박나이트 다녀왔습니다', '친구가 대구호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대구 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daeguhobaknight', 4, 8, 185, false, '2026-03-31T23:28:15.835Z', '2026-03-31T23:28:15.835Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구 나이트 비교해봤는데', '대구에서 나이트 3군데 돌아봤는데 대구호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daeguhobaknight', 5, 7, 84, false, '2026-04-26T10:40:12.119Z', '2026-04-26T10:40:12.119Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대구호박나이트 처음 가는 분들 팁', '대구호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

