INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대구바밤바나이트 다녀왔습니다', '친구가 대구바밤바나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대구 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daegubabambanight', 4, 32, 206, false, '2026-04-04T11:23:37.161Z', '2026-04-04T11:23:37.161Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구 나이트 비교해봤는데', '대구에서 나이트 3군데 돌아봤는데 대구바밤바나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daegubabambanight', 5, 19, 92, false, '2026-04-14T05:38:11.570Z', '2026-04-14T05:38:11.570Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대구바밤바나이트 처음 가는 분들 팁', '대구바밤바나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대구 나이트 중에 대구바밤바나이트이 무난하고 좋음.', NULL, NULL, 17, 74, false, '2026-04-22T20:03:35.419Z', '2026-04-22T20:03:35.419Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대구바밤바나이트 가보신 분?', '대구에서 나이트 가보려고 하는데 대구바밤바나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 6, 226, false, '2026-03-30T04:20:17.713Z', '2026-03-30T04:20:17.713Z');

-- ── 대구토토가나이트 (대구 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구토토가나이트 첫 방문 후기', '대구에서 나이트 찾다가 대구토토가나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'daegutotoganight', 5, 25, 168, false, '2026-04-15T21:53:47.483Z', '2026-04-15T21:53:47.483Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 대구토토가나이트 다녀왔습니다', '친구가 대구토토가나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 대구 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'daegutotoganight', 4, 17, 249, false, '2026-04-20T19:20:03.788Z', '2026-04-20T19:20:03.788Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대구 나이트 비교해봤는데', '대구에서 나이트 3군데 돌아봤는데 대구토토가나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'daegutotoganight', 5, 25, 77, false, '2026-03-31T20:36:26.368Z', '2026-03-31T20:36:26.368Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '대구토토가나이트 처음 가는 분들 팁', '대구토토가나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

대구 나이트 중에 대구토토가나이트이 무난하고 좋음.', NULL, NULL, 30, 209, false, '2026-04-10T12:53:24.370Z', '2026-04-10T12:53:24.370Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '대구토토가나이트 가보신 분?', '대구에서 나이트 가보려고 하는데 대구토토가나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 214, false, '2026-04-18T07:13:44.491Z', '2026-04-18T07:13:44.491Z');

