INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '광주토토밤나이트 첫 방문 후기', '광주에서 나이트 찾다가 광주토토밤나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gwangjutotonight', 5, 13, 151, false, '2026-04-28T13:05:44.464Z', '2026-04-28T13:05:44.464Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 광주토토밤나이트 다녀왔습니다', '친구가 광주토토밤나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 광주 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gwangjutotonight', 4, 10, 113, false, '2026-04-18T11:05:03.253Z', '2026-04-18T11:05:03.253Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '광주 나이트 비교해봤는데', '광주에서 나이트 3군데 돌아봤는데 광주토토밤나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gwangjutotonight', 5, 7, 184, false, '2026-04-05T08:39:32.343Z', '2026-04-05T08:39:32.343Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '광주토토밤나이트 처음 가는 분들 팁', '광주토토밤나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

광주 나이트 중에 광주토토밤나이트이 무난하고 좋음.', NULL, NULL, 11, 75, false, '2026-04-24T21:01:24.411Z', '2026-04-24T21:01:24.411Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '광주토토밤나이트 가보신 분?', '광주에서 나이트 가보려고 하는데 광주토토밤나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 15, 121, false, '2026-04-12T03:50:20.399Z', '2026-04-12T03:50:20.399Z');

-- ── 광주첨단엠파나이트 (광주 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '광주첨단엠파나이트 첫 방문 후기', '광주에서 나이트 찾다가 광주첨단엠파나이트 갔는데 진짜 괜찮았음. 댄스홀 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gwangjucheomdanempanight', 5, 28, 108, false, '2026-04-12T16:06:17.905Z', '2026-04-12T16:06:17.905Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 광주첨단엠파나이트 다녀왔습니다', '친구가 광주첨단엠파나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 광주 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gwangjucheomdanempanight', 4, 16, 217, false, '2026-04-10T05:18:54.365Z', '2026-04-10T05:18:54.365Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '광주 나이트 비교해봤는데', '광주에서 나이트 3군데 돌아봤는데 광주첨단엠파나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gwangjucheomdanempanight', 5, 17, 237, false, '2026-04-11T12:12:21.577Z', '2026-04-11T12:12:21.577Z');
