INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '광주MGM나이트 가보신 분?', '광주에서 나이트 가보려고 하는데 광주MGM나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 8, 172, false, '2026-04-23T10:19:16.812Z', '2026-04-23T10:19:16.812Z');

