INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정클럽 하입 솔직후기', '압구정 클럽 중에 압구정클럽 하입 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'apgujeongclub-hype', 5, 29, 90, false, '2026-04-05T02:36:55.550Z', '2026-04-05T02:36:55.550Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 압구정클럽 하입 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. 힙합, R&B 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 압구정에서 밤놀이 하려면 여기가 답인듯.', 'apgujeongclub-hype', 4, 25, 236, false, '2026-04-03T16:17:55.391Z', '2026-04-03T16:17:55.391Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정클럽 하입 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 압구정에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'apgujeongclub-hype', 4, 20, 180, false, '2026-04-08T07:04:31.401Z', '2026-04-08T07:04:31.401Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '압구정클럽 하입 처음 가는 분들 팁', '압구정클럽 하입 몇 번 가봤는데 알게 된 것들 공유함.

