INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정클럽 캔디맨 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 압구정에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'apgujeongclub-candyman', 4, 30, 73, false, '2026-04-15T01:59:38.366Z', '2026-04-15T01:59:38.366Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '압구정클럽 캔디맨 처음 가는 분들 팁', '압구정클럽 캔디맨 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

압구정 클럽 중에 압구정클럽 캔디맨이 무난하고 좋음.', NULL, NULL, 18, 143, false, '2026-04-21T09:31:16.295Z', '2026-04-21T09:31:16.295Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '압구정클럽 캔디맨 가보신 분?', '압구정에서 클럽 가보려고 하는데 압구정클럽 캔디맨 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 5, 108, false, '2026-04-14T14:30:19.544Z', '2026-04-14T14:30:19.544Z');

-- ── 압구정클럽 무인 (압구정 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정클럽 무인 솔직후기', '압구정 클럽 중에 압구정클럽 무인 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'apgujeongclub-muin', 5, 26, 90, false, '2026-04-07T15:50:00.064Z', '2026-04-07T15:50:00.064Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 압구정클럽 무인 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. 아프로비트, 레게톤 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 압구정에서 밤놀이 하려면 여기가 답인듯.', 'apgujeongclub-muin', 4, 33, 203, false, '2026-03-30T18:28:49.532Z', '2026-03-30T18:28:49.532Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정클럽 무인 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 압구정에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'apgujeongclub-muin', 4, 29, 164, false, '2026-04-24T07:35:17.784Z', '2026-04-24T07:35:17.784Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '압구정클럽 무인 처음 가는 분들 팁', '압구정클럽 무인 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
