INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 이태원클럽 메이드 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. 힙합, R&B 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 이태원에서 밤놀이 하려면 여기가 답인듯.', 'itaewonclub-maid', 4, 31, 126, false, '2026-04-13T09:02:51.840Z', '2026-04-13T09:02:51.840Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원클럽 메이드 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 이태원에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'itaewonclub-maid', 4, 17, 219, false, '2026-04-11T00:39:38.835Z', '2026-04-11T00:39:38.835Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '이태원클럽 메이드 처음 가는 분들 팁', '이태원클럽 메이드 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

이태원 클럽 중에 이태원클럽 메이드이 무난하고 좋음.', NULL, NULL, 12, 178, false, '2026-04-02T15:36:37.983Z', '2026-04-02T15:36:37.983Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '이태원클럽 메이드 가보신 분?', '이태원에서 클럽 가보려고 하는데 이태원클럽 메이드 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 30, 152, false, '2026-04-27T17:59:08.139Z', '2026-04-27T17:59:08.139Z');

-- ── 이태원클럽 프리즘 (이태원 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원클럽 프리즘 솔직후기', '이태원 클럽 중에 이태원클럽 프리즘 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'itaewonclub-prism', 5, 31, 140, false, '2026-04-04T02:07:46.267Z', '2026-04-04T02:07:46.267Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 이태원클럽 프리즘 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, 하우스 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 이태원에서 밤놀이 하려면 여기가 답인듯.', 'itaewonclub-prism', 4, 25, 192, false, '2026-04-15T06:59:22.860Z', '2026-04-15T06:59:22.860Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원클럽 프리즘 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 이태원에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'itaewonclub-prism', 4, 22, 238, false, '2026-04-09T05:36:40.083Z', '2026-04-09T05:36:40.083Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '이태원클럽 프리즘 처음 가는 분들 팁', '이태원클럽 프리즘 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

이태원 클럽 중에 이태원클럽 프리즘이 무난하고 좋음.', NULL, NULL, 34, 227, false, '2026-03-31T04:08:46.870Z', '2026-03-31T04:08:46.870Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '이태원클럽 프리즘 가보신 분?', '이태원에서 클럽 가보려고 하는데 이태원클럽 프리즘 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 25, 159, false, '2026-03-31T09:32:08.967Z', '2026-03-31T09:32:08.967Z');

-- ── 이태원개판포차 (이태원 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원개판포차 솔직후기', '이태원 클럽 중에 이태원개판포차 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'itaewongaepanpocha', 5, 26, 64, false, '2026-04-25T18:40:59.374Z', '2026-04-25T18:40:59.374Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 이태원개판포차 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. 포차 스타일, K-POP 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 이태원에서 밤놀이 하려면 여기가 답인듯.', 'itaewongaepanpocha', 4, 10, 143, false, '2026-04-15T11:50:14.985Z', '2026-04-15T11:50:14.985Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원개판포차 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 이태원에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'itaewongaepanpocha', 4, 24, 57, false, '2026-04-01T13:02:42.346Z', '2026-04-01T13:02:42.346Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '이태원개판포차 처음 가는 분들 팁', '이태원개판포차 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
