INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '이태원개판포차 가보신 분?', '이태원에서 클럽 가보려고 하는데 이태원개판포차 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 60, false, '2026-04-10T08:07:35.563Z', '2026-04-10T08:07:35.563Z');

