-- ── 홍대클럽 메이드 (홍대 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대클럽 메이드 솔직후기', '홍대 클럽 중에 홍대클럽 메이드 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'hongdaeclub-maid', 5, 11, 237, false, '2026-04-28T10:37:14.889Z', '2026-04-28T10:37:14.889Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 홍대클럽 메이드 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. K-POP, 힙합 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 홍대에서 밤놀이 하려면 여기가 답인듯.', 'hongdaeclub-maid', 4, 12, 216, false, '2026-04-08T19:51:10.699Z', '2026-04-08T19:51:10.699Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대클럽 메이드 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 홍대에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'hongdaeclub-maid', 4, 32, 144, false, '2026-04-05T09:18:06.728Z', '2026-04-05T09:18:06.728Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '홍대클럽 메이드 처음 가는 분들 팁', '홍대클럽 메이드 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

홍대 클럽 중에 홍대클럽 메이드이 무난하고 좋음.', NULL, NULL, 32, 234, false, '2026-04-28T00:40:17.835Z', '2026-04-28T00:40:17.835Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '홍대클럽 메이드 가보신 분?', '홍대에서 클럽 가보려고 하는데 홍대클럽 메이드 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 124, false, '2026-04-02T16:27:13.286Z', '2026-04-02T16:27:13.286Z');

-- ── 홍대클럽 도깨비 (홍대 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대클럽 도깨비 솔직후기', '홍대 클럽 중에 홍대클럽 도깨비 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'hongdaeclub-dokkaebi', 5, 16, 110, false, '2026-04-02T13:07:10.320Z', '2026-04-02T13:07:10.320Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 홍대클럽 도깨비 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, 한국적 감성 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 홍대에서 밤놀이 하려면 여기가 답인듯.', 'hongdaeclub-dokkaebi', 4, 17, 243, false, '2026-04-07T06:09:58.007Z', '2026-04-07T06:09:58.007Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대클럽 도깨비 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 홍대에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'hongdaeclub-dokkaebi', 4, 7, 102, false, '2026-04-25T19:42:35.674Z', '2026-04-25T19:42:35.674Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '홍대클럽 도깨비 처음 가는 분들 팁', '홍대클럽 도깨비 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

홍대 클럽 중에 홍대클럽 도깨비이 무난하고 좋음.', NULL, NULL, 20, 229, false, '2026-04-09T19:15:54.048Z', '2026-04-09T19:15:54.048Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '홍대클럽 도깨비 가보신 분?', '홍대에서 클럽 가보려고 하는데 홍대클럽 도깨비 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 20, 143, false, '2026-04-15T05:56:29.150Z', '2026-04-15T05:56:29.150Z');

