INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '서울반얀트리 솔직후기', '서울 클럽 중에 서울반얀트리 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'seoulbanyantree', 5, 18, 72, false, '2026-04-02T16:39:03.615Z', '2026-04-02T16:39:03.615Z');
