INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '서울반얀트리 가보신 분?', '서울에서 클럽 가보려고 하는데 서울반얀트리 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 29, 218, false, '2026-04-08T11:07:35.957Z', '2026-04-08T11:07:35.957Z');

-- ── 일산클럽 CJ (일산 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산클럽 CJ 솔직후기', '일산 클럽 중에 일산클럽 CJ 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'ilsanclub-cj', 5, 9, 57, false, '2026-04-16T03:18:17.213Z', '2026-04-16T03:18:17.213Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 일산클럽 CJ 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, 일산 유일 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 일산에서 밤놀이 하려면 여기가 답인듯.', 'ilsanclub-cj', 4, 25, 198, false, '2026-04-03T05:56:16.144Z', '2026-04-03T05:56:16.144Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산클럽 CJ 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 일산에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'ilsanclub-cj', 4, 9, 127, false, '2026-04-11T08:33:18.807Z', '2026-04-11T08:33:18.807Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '일산클럽 CJ 처음 가는 분들 팁', '일산클럽 CJ 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

일산 클럽 중에 일산클럽 CJ이 무난하고 좋음.', NULL, NULL, 10, 74, false, '2026-04-03T00:10:06.263Z', '2026-04-03T00:10:06.263Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산클럽 CJ 가보신 분?', '일산에서 클럽 가보려고 하는데 일산클럽 CJ 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 14, 113, false, '2026-04-23T14:30:49.321Z', '2026-04-23T14:30:49.321Z');

-- ── 의정부아레나 (의정부 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '의정부아레나 솔직후기', '의정부 클럽 중에 의정부아레나 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'uijeongbuarena', 5, 28, 236, false, '2026-04-27T04:34:17.553Z', '2026-04-27T04:34:17.553Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 의정부아레나 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, 힙합 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 의정부에서 밤놀이 하려면 여기가 답인듯.', 'uijeongbuarena', 4, 20, 236, false, '2026-04-24T17:09:07.482Z', '2026-04-24T17:09:07.482Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '의정부아레나 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 의정부에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'uijeongbuarena', 4, 16, 236, false, '2026-04-08T02:43:42.909Z', '2026-04-08T02:43:42.909Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '의정부아레나 처음 가는 분들 팁', '의정부아레나 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

의정부 클럽 중에 의정부아레나이 무난하고 좋음.', NULL, NULL, 10, 237, false, '2026-04-10T05:46:29.512Z', '2026-04-10T05:46:29.512Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '의정부아레나 가보신 분?', '의정부에서 클럽 가보려고 하는데 의정부아레나 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 24, 235, false, '2026-04-14T00:30:18.079Z', '2026-04-14T00:30:18.079Z');

-- ── 용인사거리별밤 (용인 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '용인사거리별밤 솔직후기', '용인 클럽 중에 용인사거리별밤 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'yonginbyeolbam', 5, 15, 226, false, '2026-04-07T12:46:23.738Z', '2026-04-07T12:46:23.738Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 용인사거리별밤 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, K-POP 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 용인에서 밤놀이 하려면 여기가 답인듯.', 'yonginbyeolbam', 4, 34, 137, false, '2026-04-09T17:59:14.671Z', '2026-04-09T17:59:14.671Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '용인사거리별밤 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 용인에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'yonginbyeolbam', 4, 28, 168, false, '2026-04-03T05:35:56.313Z', '2026-04-03T05:35:56.313Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '용인사거리별밤 처음 가는 분들 팁', '용인사거리별밤 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

용인 클럽 중에 용인사거리별밤이 무난하고 좋음.', NULL, NULL, 26, 94, false, '2026-04-22T09:18:34.162Z', '2026-04-22T09:18:34.162Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '용인사거리별밤 가보신 분?', '용인에서 클럽 가보려고 하는데 용인사거리별밤 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 29, 220, false, '2026-04-25T19:14:39.417Z', '2026-04-25T19:14:39.417Z');

