INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '인천파라다이스씨티 가보신 분?', '인천에서 클럽 가보려고 하는데 인천파라다이스씨티 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 103, false, '2026-04-19T20:33:49.167Z', '2026-04-19T20:33:49.167Z');

-- ── 청주클럽 슈퍼문 (청주 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청주클럽 슈퍼문 솔직후기', '청주 클럽 중에 청주클럽 슈퍼문 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'cheongju-supermoon', 5, 23, 244, false, '2026-04-27T21:42:53.870Z', '2026-04-27T21:42:53.870Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 청주클럽 슈퍼문 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. EDM, 힙합 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 청주에서 밤놀이 하려면 여기가 답인듯.', 'cheongju-supermoon', 4, 7, 53, false, '2026-04-07T21:32:07.389Z', '2026-04-07T21:32:07.389Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '청주클럽 슈퍼문 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 청주에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'cheongju-supermoon', 4, 15, 249, false, '2026-03-31T19:50:28.548Z', '2026-03-31T19:50:28.548Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '청주클럽 슈퍼문 처음 가는 분들 팁', '청주클럽 슈퍼문 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

청주 클럽 중에 청주클럽 슈퍼문이 무난하고 좋음.', NULL, NULL, 21, 241, false, '2026-04-14T05:52:01.386Z', '2026-04-14T05:52:01.386Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '청주클럽 슈퍼문 가보신 분?', '청주에서 클럽 가보려고 하는데 청주클럽 슈퍼문 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 20, 65, false, '2026-04-27T23:38:36.175Z', '2026-04-27T23:38:36.175Z');

