INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '대전설탕클럽 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 대전에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'daejeonsugarclub', 4, 7, 168, false, '2026-04-19T03:28:44.473Z', '2026-04-19T03:28:44.473Z');
