INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '압구정라운지 디엠 분위기 최고', '조용하게 한 잔 하고 싶을 때 압구정라운지 디엠 감. 압구정에서 이런 분위기 찾기 쉽지 않은데 여기는 확실히 다름. 인테리어가 고급스럽고 음악도 잔잔해서 대화하기 좋음. 데이트 코스로 추천.', 'apgujeonglounge-dm', 5, 11, 235, false, '2026-04-09T22:01:46.008Z', '2026-04-09T22:01:46.008Z');
