INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '장안동호빠 빵빵 다녀온 후기 (여성)', '친구랑 둘이서 장안동호빠 빵빵 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 장안동 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'jangandonghoppa-bbangbbang', 5, 25, 232, false, '2026-03-31T00:34:55.018Z', '2026-03-31T00:34:55.018Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '장안동 호빠 찾는 분들 참고', '장안동호빠 빵빵 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 유쾌한 분위기, 합리적 가격 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'jangandonghoppa-bbangbbang', 5, 31, 125, false, '2026-04-25T03:58:54.192Z', '2026-04-25T03:58:54.192Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '장안동호빠 빵빵 처음 가는 분들 팁', '장안동호빠 빵빵 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

