INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '건대호빠 W 다녀온 후기 (여성)', '친구랑 둘이서 건대호빠 W 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 건대 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'geondaehoppa-w', 5, 14, 72, false, '2026-04-27T05:42:38.740Z', '2026-04-27T05:42:38.740Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '건대 호빠 찾는 분들 참고', '건대호빠 W 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 미니멀 인테리어, K-POP 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'geondaehoppa-w', 5, 22, 75, false, '2026-04-15T17:07:33.445Z', '2026-04-15T17:07:33.445Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '건대호빠 W 처음 가는 분들 팁', '건대호빠 W 몇 번 가봤는데 알게 된 것들 공유함.

