INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '수원호빠 아우라 다녀온 후기 (여성)', '친구랑 둘이서 수원호빠 아우라 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 수원 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'suwonhoppa-aura', 5, 33, 118, false, '2026-04-08T02:24:26.601Z', '2026-04-08T02:24:26.601Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '수원 호빠 찾는 분들 참고', '수원호빠 아우라 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 인계동 위치, 경력 호스트 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'suwonhoppa-aura', 5, 30, 187, false, '2026-04-07T03:46:53.381Z', '2026-04-07T03:46:53.381Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '수원호빠 아우라 처음 가는 분들 팁', '수원호빠 아우라 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

수원 호빠 중에 수원호빠 아우라이 무난하고 좋음.', NULL, NULL, 15, 80, false, '2026-04-02T19:02:05.207Z', '2026-04-02T19:02:05.207Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '수원호빠 아우라 가보신 분?', '수원에서 호빠 가보려고 하는데 수원호빠 아우라 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 16, 116, false, '2026-04-21T09:39:53.721Z', '2026-04-21T09:39:53.721Z');

