INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '부산호빠 맨즈 다녀온 후기 (여성)', '친구랑 둘이서 부산호빠 맨즈 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 부산 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'busanhoppa-menz', 5, 25, 129, false, '2026-04-01T12:16:31.365Z', '2026-04-01T12:16:31.365Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '부산 호빠 찾는 분들 참고', '부산호빠 맨즈 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 광안리 위치, 부산 감성 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'busanhoppa-menz', 5, 5, 94, false, '2026-04-02T17:05:51.408Z', '2026-04-02T17:05:51.408Z');
