INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '해운대 호빠 찾는 분들 참고', '해운대호빠 벨벳 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 관광지구 위치, 차분한 분위기 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'haeundaehoppa-velvet', 5, 10, 224, false, '2026-04-25T06:03:07.482Z', '2026-04-25T06:03:07.482Z');
