INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강남호빠 플러팅 다녀온 후기 (여성)', '친구랑 둘이서 강남호빠 플러팅 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 강남 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'gangnam-hoppa-flirting', 5, 21, 116, false, '2026-04-20T19:32:09.121Z', '2026-04-20T19:32:09.121Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강남 호빠 찾는 분들 참고', '강남호빠 플러팅 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 분위기 잡은 인테리어, 프라이빗 부스 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'gangnam-hoppa-flirting', 5, 23, 97, false, '2026-04-19T09:44:33.618Z', '2026-04-19T09:44:33.618Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '강남호빠 플러팅 처음 가는 분들 팁', '강남호빠 플러팅 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
2. 깔끔한 캐주얼이면 충분
3. 택시 타고 가는 게 편함
4. 혼자 가도 전혀 어색하지 않음

강남 호빠 중에 강남호빠 플러팅이 무난하고 좋음.', NULL, NULL, 27, 52, false, '2026-04-20T05:52:35.834Z', '2026-04-20T05:52:35.834Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '강남호빠 플러팅 가보신 분?', '강남에서 호빠 가보려고 하는데 강남호빠 플러팅 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 18, 62, false, '2026-04-10T01:07:26.432Z', '2026-04-10T01:07:26.432Z');

-- ── 장안동호빠 플렉스 (장안동 호빠) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '장안동호빠 플렉스 다녀온 후기 (여성)', '친구랑 둘이서 장안동호빠 플렉스 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 장안동 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'jangandong-hoppa-flex', 5, 12, 238, false, '2026-04-25T23:19:42.604Z', '2026-04-25T23:19:42.604Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '장안동 호빠 찾는 분들 참고', '장안동호빠 플렉스 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 예약 시스템, 화려한 인테리어 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'jangandong-hoppa-flex', 5, 24, 216, false, '2026-04-24T15:14:03.481Z', '2026-04-24T15:14:03.481Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '장안동호빠 플렉스 처음 가는 분들 팁', '장안동호빠 플렉스 몇 번 가봤는데 알게 된 것들 공유함.

