INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '전주호빠 갤러리 다녀온 후기 (여성)', '친구랑 둘이서 전주호빠 갤러리 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 전주 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'jeonju-hoppa-gallery', 5, 17, 182, false, '2026-04-16T17:05:05.381Z', '2026-04-16T17:05:05.381Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '전주 호빠 찾는 분들 참고', '전주호빠 갤러리 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 갤러리 콘셉트, 소규모 친밀 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'jeonju-hoppa-gallery', 5, 17, 182, false, '2026-04-04T11:33:31.556Z', '2026-04-04T11:33:31.556Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '전주호빠 갤러리 처음 가는 분들 팁', '전주호빠 갤러리 몇 번 가봤는데 알게 된 것들 공유함.

