INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '전주호빠 갤러리 가보신 분?', '전주에서 호빠 가보려고 하는데 전주호빠 갤러리 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 33, 125, false, '2026-04-07T23:47:14.175Z', '2026-04-07T23:47:14.175Z');

-- ── 홍대호빠 (홍대 호빠) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대호빠 다녀온 후기 (여성)', '친구랑 둘이서 홍대호빠 갔는데 되게 재밌었음. 호스트분들이 대화를 잘 이끌어줘서 어색한 순간이 없었음. 홍대 쪽에서 여기만한 데 없는 것 같음. 분위기도 깔끔하고 안전한 느낌이어서 다음에 또 가려구요.', 'hongdae-hoppa', 5, 8, 193, false, '2026-04-11T10:58:02.603Z', '2026-04-11T10:58:02.603Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '홍대 호빠 찾는 분들 참고', '홍대호빠 몇 번째 방문인데 항상 만족함. 호스트 선택폭이 넓어서 좋고 강요하는 분위기가 아니라 편함. 특히 24시간 영업, 가라오케 부분이 마음에 듦. 친구들한테도 추천해줬더니 다들 괜찮다고 하더라.', 'hongdae-hoppa', 5, 10, 77, false, '2026-04-12T14:48:15.735Z', '2026-04-12T14:48:15.735Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '홍대호빠 처음 가는 분들 팁', '홍대호빠 몇 번 가봤는데 알게 된 것들 공유함.

1. 주말은 10시 이후가 피크
