INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '홍대호빠 가보신 분?', '홍대에서 호빠 가보려고 하는데 홍대호빠 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 33, 211, false, '2026-04-28T09:51:40.256Z', '2026-04-28T09:51:40.256Z');

-- ── 강서호박나이트 (강서 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강서호박나이트 첫 방문 후기', '강서에서 나이트 찾다가 강서호박나이트 갔는데 진짜 괜찮았음. 생밴드 라이브, 넓은 댄스 플로어 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'gangseo-hobak', 5, 6, 189, false, '2026-04-10T12:33:54.544Z', '2026-04-10T12:33:54.544Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 강서호박나이트 다녀왔습니다', '친구가 강서호박나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 강서 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'gangseo-hobak', 4, 9, 70, false, '2026-04-07T08:47:55.255Z', '2026-04-07T08:47:55.255Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '강서 나이트 비교해봤는데', '강서에서 나이트 3군데 돌아봤는데 강서호박나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'gangseo-hobak', 5, 34, 231, false, '2026-04-18T00:10:10.877Z', '2026-04-18T00:10:10.877Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '강서호박나이트 처음 가는 분들 팁', '강서호박나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 가장 좋은 시간대는 금~토 21:00~02:00
2. 복장은 캐주얼 정장
3. 화곡역에서 가까움
4. 혼자 가도 전혀 어색하지 않음

강서 나이트 중에 강서호박나이트이 무난하고 좋음.', NULL, NULL, 30, 199, false, '2026-04-24T01:07:48.480Z', '2026-04-24T01:07:48.480Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '강서호박나이트 가보신 분?', '강서에서 나이트 가보려고 하는데 강서호박나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 22, 220, false, '2026-03-31T10:54:21.629Z', '2026-03-31T10:54:21.629Z');

-- ── 일산화정터널나이트 (일산 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산화정터널나이트 첫 방문 후기', '일산에서 나이트 찾다가 일산화정터널나이트 갔는데 진짜 괜찮았음. 터널형 인테리어, 라이브 밴드 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'ilsan-hwajung-tunnel', 5, 6, 50, false, '2026-04-07T01:27:52.711Z', '2026-04-07T01:27:52.711Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 일산화정터널나이트 다녀왔습니다', '친구가 일산화정터널나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 일산 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'ilsan-hwajung-tunnel', 4, 27, 162, false, '2026-04-09T11:36:48.823Z', '2026-04-09T11:36:48.823Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산 나이트 비교해봤는데', '일산에서 나이트 3군데 돌아봤는데 일산화정터널나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'ilsan-hwajung-tunnel', 5, 26, 161, false, '2026-04-16T02:22:06.974Z', '2026-04-16T02:22:06.974Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '일산화정터널나이트 처음 가는 분들 팁', '일산화정터널나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 가장 좋은 시간대는 금~토 21:00~02:00
2. 복장은 캐주얼 정장
3. 화정역에서 가까움
4. 혼자 가도 전혀 어색하지 않음

일산 나이트 중에 일산화정터널나이트이 무난하고 좋음.', NULL, NULL, 31, 221, false, '2026-04-02T15:17:40.015Z', '2026-04-02T15:17:40.015Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산화정터널나이트 가보신 분?', '일산에서 나이트 가보려고 하는데 일산화정터널나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 16, 209, false, '2026-04-10T16:48:18.457Z', '2026-04-10T16:48:18.457Z');

-- ── 일산물나이트 (일산 나이트) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산물나이트 첫 방문 후기', '일산에서 나이트 찾다가 일산물나이트 갔는데 진짜 괜찮았음. 남녀 비율 관리, 메인홀+서브라운지 이런 특징이 있어서 분위기가 딱 내 스타일이었음. 밴드 라이브 퀄리티가 생각보다 높아서 놀람. 처음이라 좀 쭈뼛거렸는데 옆 테이블 분이 먼저 말 걸어줘서 금방 적응함. 다음 주말에 또 갈 예정.', 'ilsan-mul-night', 5, 32, 126, false, '2026-04-24T21:21:01.444Z', '2026-04-24T21:21:01.444Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '금토 밤 일산물나이트 다녀왔습니다', '친구가 일산물나이트 추천해줘서 토요일에 갔는데 사람 꽤 많더라. 일산 쪽에서는 여기가 젤 유명한 듯. 음악은 트로트 위주인데 올드팝도 섞어주니까 다양하게 즐길 수 있었음. 댄스 플로어 크기도 적당하고 조명도 좋았음. 주차는 좀 일찍 가야 자리 있을듯.', 'ilsan-mul-night', 4, 15, 249, false, '2026-04-03T18:01:01.985Z', '2026-04-03T18:01:01.985Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '일산 나이트 비교해봤는데', '일산에서 나이트 3군데 돌아봤는데 일산물나이트이 제일 나았음. 시설도 깨끗하고 음향도 좋고. 특히 밴드 실력이 다름. 스텝 잘 못 춰도 분위기에 취해서 그냥 몸이 움직여짐ㅋㅋ 혼자 온 사람도 꽤 많아서 부담없이 갈 수 있음.', 'ilsan-mul-night', 5, 18, 234, false, '2026-04-14T16:07:45.176Z', '2026-04-14T16:07:45.176Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '일산물나이트 처음 가는 분들 팁', '일산물나이트 몇 번 가봤는데 알게 된 것들 공유함.

1. 가장 좋은 시간대는 토 23:00~01:00
2. 복장은 캐주얼 정장
3. 대화역에서 가까움
4. 혼자 가도 전혀 어색하지 않음

일산 나이트 중에 일산물나이트이 무난하고 좋음.', NULL, NULL, 20, 188, false, '2026-04-16T17:14:57.394Z', '2026-04-16T17:14:57.394Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '일산물나이트 가보신 분?', '일산에서 나이트 가보려고 하는데 일산물나이트 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 23, 58, false, '2026-03-30T18:53:19.214Z', '2026-03-30T18:53:19.214Z');

-- ── 이태원클럽 세비지 (이태원 클럽) ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원클럽 세비지 솔직후기', '이태원 클럽 중에 이태원클럽 세비지 처음 가봤는데 음악이 진짜 좋았음. DJ가 분위기 읽는 능력이 대단함. EDM 좋아하는 사람이면 무조건 가야 됨. 드레스코드 있으니까 운동화는 안 됨. 밤 12시 넘으면 대기 있을 수 있으니 일찍 가는 게 좋음.', 'itaewon-savage', 5, 12, 140, false, '2026-04-12T00:51:32.661Z', '2026-04-12T00:51:32.661Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '주말 이태원클럽 세비지 갔다왔음', '금요일 밤에 갔는데 줄 서서 20분 기다림. 근데 들어가니까 기다린 보람 있었음. Funktion-One 사운드, 게스트 DJ 이게 진짜 좋았고 사운드 시스템이 제대로임. VIP 쪽은 테이블 잡으면 편하게 놀 수 있음. 이태원에서 밤놀이 하려면 여기가 답인듯.', 'itaewon-savage', 4, 5, 199, false, '2026-04-15T05:47:42.556Z', '2026-04-15T05:47:42.556Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('reviews', '이태원클럽 세비지 분위기 어떤지 궁금한 분들께', '저번 주 처음 가봤는데 이태원에서 이 정도 클럽는 처음이었음. 조명이랑 인테리어가 확실히 돈 쓴 느낌. 음악 장르도 다양하게 틀어줌. 사람들 매너도 좋고 스태프들도 친절했음. 단점이라면 주말엔 너무 사람 많다는 거?', 'itaewon-savage', 4, 28, 117, false, '2026-04-12T21:13:17.645Z', '2026-04-12T21:13:17.645Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('tips', '이태원클럽 세비지 처음 가는 분들 팁', '이태원클럽 세비지 몇 번 가봤는데 알게 된 것들 공유함.

1. 가장 좋은 시간대는 금 24:00~03:00
2. 복장은 자유 (슬리퍼/반바지 제외)
3. 이태원역에서 가까움
4. 혼자 가도 전혀 어색하지 않음

이태원 클럽 중에 이태원클럽 세비지이 무난하고 좋음.', NULL, NULL, 34, 96, false, '2026-04-17T12:34:18.943Z', '2026-04-17T12:34:18.943Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('discussion', '이태원클럽 세비지 가보신 분?', '이태원에서 클럽 가보려고 하는데 이태원클럽 세비지 어떤지 아시는 분 계신가요? 처음이라 좀 긴장되는데 혼자 가도 괜찮을까요? 분위기랑 사람들 매너 어떤지 알려주시면 감사하겠습니다.', NULL, NULL, 12, 105, false, '2026-04-07T21:23:55.570Z', '2026-04-07T21:23:55.570Z');

-- ── 자유게시판 시드 ──
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '금요일인데 어디 갈지 못 정했음', '강남 쪽에서 놀건데 클럽이랑 나이트 고민 중.. 클럽은 시끄럽고 나이트는 나이대가 좀 있고.. 추천 좀요', NULL, NULL, 52, 344, false, '2026-03-31T11:35:15.415Z', '2026-03-31T20:39:05.166Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '혼자 나이트 간 썰', '처음에 개쫄았는데 막상 가니까 혼자 온 사람 진짜 많더라ㅋㅋ 옆 테이블 아저씨가 먼저 춤 신청해주셔서 감동받음. 이제 매주 감', NULL, NULL, 50, 392, false, '2026-04-26T23:25:30.707Z', '2026-04-22T06:31:17.035Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '클럽 드레스코드 질문', '이번 주말 강남 클럽 가려는데 운동화 되나요? 찾아보니까 어떤 데는 되고 어떤 데는 안 되고 헷갈림', NULL, NULL, 30, 178, false, '2026-03-30T15:07:22.232Z', '2026-04-21T06:40:00.188Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '부산 출장인데 밤에 갈 곳', '해운대 근처에서 숙소 잡았는데 밤에 혼자 갈 만한 곳 있나요? 조용한 데가 좋긴 한데 사람 만나고 싶기도 하고', NULL, NULL, 34, 244, false, '2026-04-03T14:46:10.099Z', '2026-04-14T03:52:09.257Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '나이트 처음인데 스텝 몰라도 괜찮나요', '유튜브로 지르박 봤는데 실전은 다르다고 하더라고요.. 초보자도 가면 적응 가능한가요? 주변에 같이 갈 사람도 없고', NULL, NULL, 28, 303, false, '2026-04-11T11:21:34.334Z', '2026-04-09T05:15:46.837Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '오늘 불금인데 같이 갈 사람', '강남 쪽에서 놀 건데 남자 2명임. 나이트든 클럽이든 같이 갈 사람 구함. 20대 후반 직장인', NULL, NULL, 37, 179, false, '2026-04-26T03:56:36.478Z', '2026-04-22T00:56:41.744Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '라운지 vs 클럽 뭐가 더 좋음?', '데이트로 가려는데 라운지가 나을까 클럽이 나을까.. 여자친구가 시끄러운 거 별로 안 좋아하는데 그래도 분위기는 있었으면', NULL, NULL, 38, 197, false, '2026-04-17T05:29:34.867Z', '2026-04-04T06:59:29.601Z');
INSERT INTO posts (category, title, content, venue_slug, rating, likes, views, is_pinned, created_at, updated_at) VALUES ('free', '놀쿨에서 후기 보고 갔는데 대만족', '원래 아는 곳만 가다가 놀쿨에서 새로운 데 찾아서 갔는데 진짜 좋았음. 후기 믿어도 됨. 앞으로 여기서 계속 찾을 듯', NULL, NULL, 33, 250, false, '2026-04-05T03:55:36.291Z', '2026-04-10T00:35:51.467Z');
